#include <bits/stdc++.h>
using namespace std;
int main(){
    int n; cin >> n;
    vector<int> arr(n);
    for(int i = 0; i < n; i++) cin >> arr[i];
    int k; cin >> k;
    int count = 0;
    int prefix_sum = 0;
    unordered_map<int, int> seen = {{0, 1}};
    for(int num : arr){
        prefix_sum += num;
        if(seen.find(prefix_sum - k) != seen.end()){
            count += seen[prefix_sum - k];
        }
        seen[prefix_sum]++;
    }
    cout << count;
}
